+
+      // Preserve fast math flags from the original select.
+
+      FastMathFlags FMF = SI.getFastMathFlags();
+
+      // Also propagate ninf/nnan from fcmp to select.
+
+      if (FCmp->hasNoNaNs())
+
+        FMF.setNoNaNs(true);
+
+      if (FCmp->hasNoInfs())
+
+        FMF.setNoInfs(true);
